INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1000001, 62, 190801, 1, 1, 2, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", "2025/01/31 12:00:00", "カリン", 0.0, 3.414, "2030/01/01 14:59:59", 1, -416.5);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1000002, 62, 190801, 1, 1, 2, "ミッションをクリアして、\n報酬をゲットしましょう！", "2025/01/31 12:00:00", "カリン", 0.0, 3.099, "2030/01/01 14:59:59", 2, -416.5);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1000003, 63, 190801, 1, 1, 2, "受け取ることができる\n報酬があるようです\n確認してみてください", "2025/01/31 12:00:00", "カリン", 0.0, 2.801, "2030/01/01 14:59:59", 3, -416.5);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1000004, 63, 190801, 2, 1, 2, "報酬がもらえますよ！\nチェックしてみてください", "2025/01/31 12:00:00", "カリン", 0.0, 0.0, "2030/01/01 14:59:59", 4, -416.5);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1000005, 64, 190801, 2, 1, 1, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", "2025/01/31 12:00:00", "カリン", 0.0, 2.12, "2030/01/01 14:59:59", 5, -363.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1000006, 64, 190801, 1, 1, 2, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", "2025/01/31 12:00:00", "カリン", 0.0, 1.68, "2030/01/01 14:59:59", 6, -363.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1000007, 64, 190801, 2, 1, 1, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", "2025/01/31 12:00:00", "カリン", 0.0, 2.33, "2030/01/01 14:59:59", 7, -363.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020101, 61, 133701, 3, 10201, 7, "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", "2025/01/31 12:00:00", "ラビリスタ", -6.0, 5.18, "2030/01/01 14:59:59", 101, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020102, 61, 133901, 1, 10201, 2, "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", "2025/01/31 12:00:00", "クリスティーナ", -2.0, 8.77, "2030/01/01 14:59:59", 201, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020103, 61, 133801, 6, 10201, 1, "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", "2025/01/31 12:00:00", "ネネカ", 0.0, 15.5, "2030/01/01 14:59:59", 301, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020201, 61, 134301, 2, 10202, 5, "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", "2025/02/28 12:00:00", "ランファ", 0.0, 9.061, "2030/01/01 14:59:59", 101, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020202, 61, 134401, 1, 10202, 2, "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", "2025/02/28 12:00:00", "チカ", 0.0, 7.699, "2030/01/01 14:59:59", 201, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020301, 61, 134601, 1, 10203, 2, "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", "2025/03/31 12:00:00", "アオイ", 0.0, 8.595, "2030/01/01 14:59:59", 101, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020302, 61, 134501, 1, 10203, 2, "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", "2025/03/31 12:00:00", "クローチェ", 0.0, 7.758, "2030/01/01 14:59:59", 201, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020401, 61, 132302, 2, 10204, 6, "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", "2025/04/30 12:00:00", "ルイズマリー", 0.0, 7.0, "2030/01/01 14:59:59", 101, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020402, 61, 132402, 1, 10204, 2, "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", "2025/04/30 12:00:00", "イロハ", 0.0, 7.904, "2030/01/01 14:59:59", 201, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020403, 61, 132502, 4, 10204, 2, "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", "2025/04/30 12:00:00", "ソノ", 0.0, 8.487, "2030/01/01 14:59:59", 301, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020502, 61, 134901, 1, 10205, 2, "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", "2025/05/31 12:00:00", "カノン", 0.0, 8.763, "2030/01/01 14:59:59", 101, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020503, 61, 134801, 1, 10205, 3, "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", "2025/05/31 12:00:00", "ツムギ", 0.0, 6.417, "2030/01/01 14:59:59", 201, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020601, 61, 135001, 3, 10206, 7, "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", "2025/06/30 12:00:00", "エリス", 0.0, 10.335, "2030/01/01 14:59:59", 101, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020602, 61, 135101, 2, 10206, 4, "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", "2025/06/30 12:00:00", "シェフィ", 0.0, 6.281, "2030/01/01 14:59:59", 201, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020603, 61, 135201, 1, 10206, 2, "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", "2025/06/30 12:00:00", "プレシア", 0.0, 12.244, "2030/01/01 14:59:59", 301, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020701, 61, 135301, 2, 10207, 8, "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", "2025/07/31 12:00:00", "クリア", 0.0, 6.339, "2030/01/01 14:59:59", 101, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020702, 61, 135401, 7, 10207, 9, "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", "2025/07/31 12:00:00", "アネモネ", 0.0, 8.184, "2030/01/01 14:59:59", 201, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020801, 61, 129101, 9, 10208, 2, "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", "2025/08/31 12:00:00", "アイラ", 0.0, 3.906, "2030/01/01 14:59:59", 101, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020802, 61, 129201, 1, 10208, 2, "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", "2025/08/31 12:00:00", "シナツ", 0.0, 14.465, "2030/01/01 14:59:59", 201, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020803, 61, 100101, 4, 10208, 3, "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", "2025/08/31 12:00:00", "ヒヨリ", 0.0, 8.662, "2030/01/01 14:59:59", 301, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020804, 61, 100301, 1, 10208, 3, "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", "2025/08/31 12:00:00", "レイ", 0.0, 10.915, "2030/01/01 14:59:59", 401, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020901, 61, 135802, 1, 10209, 7, "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", "2025/09/30 12:00:00", "ユキノ", 0.0, 6.042, "2030/01/01 14:59:59", 101, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020902, 61, 135903, 4, 10209, 1, "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", "2025/09/30 12:00:00", "サツキ", 0.0, 9.402, "2030/01/01 14:59:59", 201, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020903, 61, 136902, 8, 10209, 1, "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", "2025/09/30 12:00:00", "ルルィ", 0.0, 8.16, "2030/01/01 14:59:59", 301, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021001, 61, 137401, 3, 10210, 2, "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", "2025/10/31 12:00:00", "カスミ", 0.0, 5.0, "2030/01/01 14:59:59", 101, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021002, 61, 136001, 4, 10210, 1, "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", "2025/10/31 12:00:00", "アラクネ", 0.0, 8.12, "2030/01/01 14:59:59", 201, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021003, 61, 136202, 4, 10210, 2, "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", "2025/10/31 12:00:00", "ナーナ", 0.0, 6.386, "2030/01/01 14:59:59", 301, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021101, 61, 136402, 3, 10211, 4, "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", "2025/11/30 12:00:00", "ユイ", 0.0, 7.438, "2030/01/01 14:59:59", 101, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021102, 61, 136302, 1, 10211, 5, "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", "2025/11/30 12:00:00", "ミソラ", 0.0, 8.35, "2030/01/01 14:59:59", 201, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021201, 61, 136501, 1, 10212, 2, "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", "2025/12/31 12:00:00", "シズル", 0.0, 5.0, "2030/01/01 14:59:59", 101, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021202, 61, 137902, 1, 10212, 2, "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", "2025/12/31 12:00:00", "リノ", 0.0, 5.25, "2030/01/01 14:59:59", 201, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021203, 61, 106801, 1, 10212, 2, "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", "2025/12/31 12:00:00", "ラビリスタ", 0.0, 7.5, "2030/01/01 14:59:59", 301, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021301, 61, 126501, 1, 10213, 2, "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", "2026/01/31 12:00:00", "ライラエル", 0.0, 8.204, "2030/01/01 14:59:59", 101, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021302, 61, 129701, 1, 10213, 2, "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", "2026/01/31 12:00:00", "ネフィ＝ネラ", 0.0, 7.176, "2030/01/01 14:59:59", 201, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021303, 61, 133101, 1, 10213, 5, "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", "2026/01/31 12:00:00", "ヴァイオレット", 0.0, 8.602, "2030/01/01 14:59:59", 301, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021304, 61, 138101, 1, 10213, 3, "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", "2026/02/06 12:00:00", "ライラエル", 0.0, 10.14, "2030/01/01 14:59:59", 102, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021305, 61, 138201, 1, 10213, 7, "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", "2026/02/06 12:00:00", "ネフィ＝ネラ", 0.0, 10.152, "2030/01/01 14:59:59", 202, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021306, 61, 138001, 4, 10213, 3, "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", "2026/02/06 12:00:00", "ヴァイオレット", 0.0, 9.688, "2030/01/01 14:59:59", 302, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021307, 61, 138301, 2, 10213, 1, "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", "2026/02/12 12:00:00", "ペコリーヌ", 0.0, 5.928, "2030/01/01 14:59:59", 401, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021401, 61, 138702, 4, 10214, 2, "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", "2026/02/28 12:00:00", "ワカナ", 0.0, 9.19, "2030/01/01 14:59:59", 101, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021402, 61, 138802, 1, 10214, 3, "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", "2026/02/28 12:00:00", "シオリ", 0.0, 8.724, "2030/01/01 14:59:59", 201, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021501, 61, 138902, 4, 10215, 1, "私がへんたいふしんしゃさんって…\nただ生きているだけなのに、ひどい\n…まぁ死んでるんですけど…とか\n言ってる暇もない感じですか？", "2026/03/31 12:00:00", "グレイス", 0.0, 7.758, "2030/01/01 14:59:59", 101, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021502, 61, 139002, 6, 10215, 4, "あの、助けてください！\n私がへんたいふしんしゃさんに\nなっちゃったみたいなんです…！\nどういう意味かは私もわかりません", "2026/03/31 12:00:00", "キョウカ", 0.0, 6.375, "2030/01/01 14:59:59", 201, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021503, 61, 136902, 6, 10215, 1, "ましゃか、グレイス姉しゃまたちが\nへんたいふしんしゃさんだなんて…\n騎士しゃん。あたちたちも協力ちて\n二人の破滅エンドを回避ちましょう", "2026/03/31 12:00:00", "ルルィ", 0.0, 6.173, "2030/01/01 14:59:59", 301, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021601, 61, 139202, 6, 10216, 2, "違う世界に来ちゃうし、\n驚きの連続だけど…\nわたしも精いっぱい頑張ります！\nアストルムのみんなと一緒に！", "2026/04/30 12:00:00", "ミホ", 0.0, 4.202, "2030/01/01 14:59:59", 101, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021602, 61, 139302, 6, 10216, 1, "想定外の事象が発生したな…だが\nいかなる苦境も切り抜けてみせる\nいつもの自分とは違う姿になっても\nわたしはわたし、西住流だ", "2026/04/30 12:00:00", "マホ", 0.0, 2.842, "2030/01/01 14:59:59", 201, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021603, 61, 139402, 4, 10216, 1, "何でこんなことになっているのか\n全然わからないけど、迷ってる暇は\nないわ。黒森峰の次期隊長として、\n前進あるのみ！　これも戦車道よ！", "2026/04/30 12:00:00", "エリカ", 0.0, 4.598, "2030/01/01 14:59:59", 301, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021701, 61, 125802, 4, 10217, 3, "わたくしたちの悲願は、ロストさせ\nてしまった方々をお助けすること…\nそのためなら、どのような辛苦にも\n耐え抜いてみせます…！", "2026/05/31 12:00:00", "リリ", 0.0, 6.533, "2030/01/01 14:59:59", 101, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021702, 61, 126102, 3, 10217, 3, "みんなも。せーぎも。\nクリアも。パパ、も。\nぜったい、たすける。\nみててね。お兄。", "2026/05/31 12:00:00", "プレシア", 0.0, 5.0, "2030/01/01 14:59:59", 301, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021703, 61, 126002, 3, 10217, 4, "癒しの力を使うこと…\nもう、ためらいません！\nモネちゃんやお兄さん…\nみんなに許してもらうためにも！", "2026/05/31 12:00:00", "クリア", 0.0, 5.214, "2030/01/01 14:59:59", 201, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021704, 61, 139501, 1, 10217, 3, "ヴァルキュリア─皆様を助けたい\nという願いを、力にできるのなら…\nわたくしたちは、きっと誰にも\n負けません！　一意専心です…！", "2026/05/31 12:00:00", "リリ", 0.0, 8.781, "2030/01/01 14:59:59", 102, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021705, 61, 139601, 2, 10217, 1, "このヴァルキュリアって職業、\nまるで天使みたいな格好ですよね\nうーん…『聖女』ちゃんって\n呼ばれるよりは、マシかな？", "2026/05/31 12:00:00", "クリア", 0.0, 6.529, "2030/01/01 14:59:59", 202, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021706, 61, 139701, 3, 10217, 2, "ばるきり。もーど。\nはね。まっしろ。\nはっぴーちゃんと。おなじ。\nいいかんじ。", "2026/05/31 12:00:00", "プレシア", 0.0, 3.195, "2030/01/01 14:59:59", 302, -285.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2000001, 62, 190801, 1, 2, 2, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", "2026/04/10 12:00:00", "カリン", 0.0, 3.414, "2030/01/01 14:59:59", 1, -416.5);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2000002, 62, 190801, 1, 2, 2, "ミッションをクリアして、\n報酬をゲットしましょう！", "2026/04/10 12:00:00", "カリン", 0.0, 3.099, "2030/01/01 14:59:59", 2, -416.5);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2000003, 63, 190801, 1, 2, 2, "受け取ることができる\n報酬があるようです\n確認してみてください", "2026/04/10 12:00:00", "カリン", 0.0, 2.801, "2030/01/01 14:59:59", 3, -416.5);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2000004, 63, 190801, 2, 2, 2, "報酬がもらえますよ！\nチェックしてみてください", "2026/04/10 12:00:00", "カリン", 0.0, 0.0, "2030/01/01 14:59:59", 4, -416.5);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2000005, 64, 190801, 2, 2, 1, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", "2026/04/10 12:00:00", "カリン", 0.0, 2.12, "2030/01/01 14:59:59", 5, -363.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2000006, 64, 190801, 1, 2, 2, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", "2026/04/10 12:00:00", "カリン", 0.0, 1.68, "2030/01/01 14:59:59", 6, -363.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2000007, 64, 190801, 2, 2, 1, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", "2026/04/10 12:00:00", "カリン", 0.0, 2.33, "2030/01/01 14:59:59", 7, -363.0);
